inline DepthOrderingSnapshot test_observer_depth_ordering() {
    // 1. Define DepthProbeNode class
    class DepthProbeNode : public reaction::ObserverNode {
    public:
        void updateDepth(uint16_t depth) {
            ObserverNode::updateDepth(depth);
        }
    };

    // 2. Get thread manager instance
    auto& threadManager = reaction::ThreadManager::getInstance();

    // 3. Reset thread manager state
    threadManager.resetForTesting();

    // 4. Enable thread safety
    threadManager.enableThreadSafety();

    // 5. Create shallow and deep DepthProbeNode instances
    DepthProbeNode shallowNode;
    DepthProbeNode deepNode;

    // Set initial depths
    shallowNode.updateDepth(1);  // Shallow depth
    deepNode.updateDepth(2);     // Deeper depth

    // 6. Create NodeWeak from nodes
    auto shallowWeak = reaction::NodeWeak{std::static_pointer_cast<reaction::ObserverNode>(std::make_shared<DepthProbeNode>(shallowNode))};
    auto deepWeak = reaction::NodeWeak{std::static_pointer_cast<reaction::ObserverNode>(std::make_shared<DepthProbeNode>(deepNode))};

    // 7. Create BatchCompare instance
    reaction::BatchCompare batchCompare;

    // 8. Compare initial nodes
    bool initialResult = batchCompare.compareNodes(shallowWeak, deepWeak);

    // 9. Update depths of nodes - shallow becomes deeper than deep
    shallowNode.updateDepth(3);  // Make shallow deeper than deep
    bool shallowBeforeDeepResult = batchCompare.compareNodes(shallowWeak, deepWeak);

    // 10. Update depth of shallow node again - deep becomes deeper than shallow
